                     'J','K','L','M','N','O','P','Q','R','S',
                     'T','U','V','W','X','Y','Z' };

// 对应频率
int    weights[27] = { 186, 64, 13, 22, 32, 103, 21, 15,
                        47, 57,  1,  5, 32,  20, 57, 63,
                        15,  1, 48, 51, 80,  23,  8, 18,
                         1, 16,  1 };

// ============ 函数声明 ============
void InitHT();                               // 初始化哈夫曼树
void CreateHT();                             // 创建哈夫曼树
void Select(int range, int &s1, int &s2);    // 从森林中选择两个权值最小的根结点
void CreateHTCode();                         // 生成哈夫曼编码
void PrintHT();                              // 打印哈夫曼树结构
void PrintCode();                            // 打印字符编码
void CalcTransLength(const char *str);       // 计算报文传输长度
void DecodeInput();                          // 解码用户输入的01串
void PrintMenu();                            // 打印菜单

// ============ 主函数 ============
int main() {
