// ============ 初始化哈夫曼树 ============
void InitHT() {
    m = 2 * n - 1;  // 总结点数 = 2*27 - 1 = 53

    // 初始化叶子结点
    for (int i = 0; i < n; i++) {
        ht[i].ch     = chars[i];
        ht[i].weight = weights[i];
        ht[i].parent = -1;
        ht[i].lchild = -1;
        ht[i].rchild = -1;
        ht[i].order  = i;       // 记录原始顺序
    }

    // 初始化内部结点
    for (int i = n; i < m; i++) {
        ht[i].ch     = '#';     // 内部结点用 # 标记
        ht[i].weight = 0;
        ht[i].parent = -1;
        ht[i].lchild = -1;
        ht[i].rchild = -1;
        ht[i].order  = i;       // 后出现的 order 较大
    }
}

// ============ 选择两个权值最小的根结点 ============
// 在 [0, range) 范围内选择 parent=-1 且权值最小的两个结点
// s1 存放最小的，s2 存放次小的
// 要求：s1 的权值 <= s2 的权值，若权值相同则先出现的为 s1
void Select(int range, int &s1, int &s2) {
    int min1 = 0x7fffffff;  // 极大值
    int min2 = 0x7fffffff;

    s1 = -1;
    s2 = -1;

    for (int i = 0; i < range; i++) {
        if (ht[i].parent == -1) {  // 只考虑根结点
            int w = ht[i].weight;
            int o = ht[i].order;

            if (w < min1) {
                // 原来的最小变成次小
                min2 = min1;
                s2   = s1;
                min1 = w;
                s1   = i;
            } else if (w == min1 && s1 != -1) {
                // 权值相同，先出现的 (order小的) 优先
                if (o < ht[s1].order) {
                    min2 = min1;
                    s2   = s1;
                    min1 = w;
                    s1   = i;
                } else {
                    // 当前结点作为次小候选
                    if (w < min2 || (w == min2 && s2 != -1 && o < ht[s2].order)) {
                        min2 = w;
                        s2   = i;
                    } else if (min2 == 0x7fffffff) {
                        min2 = w;
                        s2   = i;
                    }
                }
            } else if (w < min2) {
                min2 = w;
                s2   = i;
            } else if (w == min2 && s2 != -1) {
                // 权值相同
                if (o < ht[s2].order) {
                    min2 = w;
                    s2   = i;
                }
            }
        }
    }

    // 确保 s1 的权值 <= s2 的权值
    // 若权值相等，s1 的 order < s2 的 order (先出现的在左)
    if (s1 != -1 && s2 != -1) {
        if (ht[s1].weight > ht[s2].weight) {
            int tmp = s1;
            s1 = s2;
            s2 = tmp;
        } else if (ht[s1].weight == ht[s2].weight) {
            if (ht[s1].order > ht[s2].order) {
                int tmp = s1;
                s1 = s2;
                s2 = tmp;
            }
        }
    }
}

// ============ 创建哈夫曼树 ============
void CreateHT() {
    InitHT();
    int s1, s2;

    // 构造 n-1 个内部结点 (合并 n-1 次)
    for (int i = n; i < m; i++) {
        // 在前 i 个结点中选择两个权值最小的根结点
        Select(i, s1, s2);

        // 构建新结点
        ht[s1].parent = i;
        ht[s2].parent = i;

        ht[i].lchild = s1;   // s1 为左孩子 (权值较小或先出现)
        ht[i].rchild = s2;   // s2 为右孩子
        ht[i].weight = ht[s1].weight + ht[s2].weight;
        ht[i].order  = i;
    }
}

// ============ 生成哈夫曼编码 ============
void CreateHTCode() {
    for (int i = 0; i < n; i++) {
        hc[i].ch = chars[i];

        // 从叶子向根回溯
        int child  = i;
        int parent = ht[i].parent;
        char temp[MAXLEN];
        int  pos = 0;

        while (parent != -1) {
            if (ht[parent].lchild == child) {
                temp[pos++] = '0';
            } else {
                temp[pos++] = '1';
            }
            child  = parent;
            parent = ht[parent].parent;
        }

        // 反转得到正确的编码
        hc[i].len = pos;
        for (int j = 0; j < pos; j++) {
            hc[i].bits[j] = temp[pos - 1 - j];
        }
        hc[i].bits[pos] = '\0';
    }
}

// ============ 递归打印哈夫曼树结构 ============
void PrintTreeNode(int root, int depth, char *prefix, int isLeft) {
    if (root == -1) return;

    // 打印右子树 (上方)
    if (ht[root].rchild != -1) {
        char newPrefix[MAXLEN];
        sprintf(newPrefix, "%s%s", prefix, isLeft ? "|   " : "    ");
        PrintTreeNode(ht[root].rchild, depth + 1, newPrefix, 0);
    }

    // 打印当前结点
    for (int i = 0; i < depth; i++) {
        if (i == depth - 1) {
            cout << (isLeft ? "+---" : "\\---");
        } else {
            // 根据prefix判断
            cout << prefix;
            // 简单处理
        }
    }

    // 简化版横向树打印
    if (depth == 0) {
        cout << "Root";
    }

    if (root < n) {
        // 叶子结点
        char display = ht[root].ch;
        if (display == ' ')
            cout << "[" << "SP" << ":" << ht[root].weight << "]";
        else
            cout << "[" << display << ":" << ht[root].weight << "]";
    } else {
        // 内部结点
        cout << "(" << ht[root].weight << ")";
    }
    cout << endl;

    // 打印左子树 (下方)
    if (ht[root].lchild != -1) {
        char newPrefix[MAXLEN];
        sprintf(newPrefix, "%s%s", prefix, isLeft ? "|   " : "    ");
        PrintTreeNode(ht[root].lchild, depth + 1, newPrefix, 1);
    }
}

// ============ 打印哈夫曼树结构 ============
// 采用缩进方式展示树形结构
void PrintIndentTree(int idx, int depth) {
    if (idx == -1) return;

    // 先打印右子树
    PrintIndentTree(ht[idx].rchild, depth + 1);

    // 缩进
    for (int i = 0; i < depth; i++) {
        cout << "        ";
    }

    // 打印结点信息
    if (idx < n) {
        // 叶子结点
        char c = ht[idx].ch;
        cout << "[" << idx << "] ";
        if (c == ' ')
            cout << "<SP>:";
        else
            cout << c << ":";
        cout << ht[idx].weight;
        if (strlen(hc[idx].bits) > 0) {
            cout << " (" << hc[idx].bits << ")";
        }
    } else {
        // 内部结点
        cout << "[" << idx << "] (" << ht[idx].weight << ")";
    }
    cout << endl;

    // 再打印左子树
    PrintIndentTree(ht[idx].lchild, depth + 1);
}

void PrintHT() {
    cout << endl;
    cout << "================================================" << endl;
    cout << "          哈夫曼树结构 (横向缩进显示)" << endl;
    cout << "          说明: 叶子结点显示 字符:权值(编码)" << endl;
    cout << "                内部结点显示 (权值)" << endl;
    cout << "================================================" << endl;
    PrintIndentTree(m - 1, 0);
    cout << endl;
}

// ============ 打印字符及其哈夫曼编码 ============
void PrintCode() {
    cout << "================================================" << endl;
    cout << "           字符及其哈夫曼编码" << endl;
    cout << "================================================" << endl;
    cout << "字符\t权值\t哈夫曼编码\t编码长度" << endl;
    cout << "------------------------------------------------" << endl;

    for (int i = 0; i < n; i++) {
        char c = hc[i].ch;
        cout << (c == ' ' ? "<SP>" : string(1, c)) << "\t";
        cout << ht[i].weight << "\t";
        cout << hc[i].bits << "\t\t";
        cout << hc[i].len;
        cout << endl;
    }
    cout << "================================================" << endl;
}

// ============ 计算报文传输长度 ============
// 根据哈夫曼编码计算字符串的总编码长度
void CalcTransLength(const char *str) {
    // 先建立字符到编码的映射
    int map[256];
    for (int i = 0; i < 256; i++) map[i] = -1;
    for (int i = 0; i < n; i++) {
        map[(unsigned char)hc[i].ch] = i;
    }

    cout << endl;
    cout << "================================================" << endl;
    cout << "  计算报文传输长度" << endl;
    cout << "  原文: " << str << endl;
    cout << "================================================" << endl;

    int total = 0;
    int len = strlen(str);

    cout << "逐字符编码:" << endl;
    for (int i = 0; i < len; i++) {
        char c = str[i];
        int  idx = map[(unsigned char)c];

        if (idx == -1) {
            cout << "  [" << c << "] 不在字符集中，跳过" << endl;
            continue;
        }

        cout << "  ";
        if (c == ' ')
            cout << "<SP>";
        else
            cout << c;
        cout << " -> " << hc[idx].bits
             << " (长度: " << hc[idx].len << ")" << endl;

        total += hc[idx].len;
    }

    cout << "------------------------------------------------" << endl;
    cout << "总报文传输长度: " << total << " bits" << endl;
    cout << "================================================" << endl;
}

// ============ 解码01串 ============
void DecodeInput() {
    string input;
    cout << endl;
    cout << "================================================" << endl;
    cout << "  哈夫曼解码" << endl;
    cout << "================================================" << endl;
    cout << "请输入01编码串: ";
    getline(cin, input);

    // 检查输入是否合法 (只包含0和1)
    for (size_t i = 0; i < input.length(); i++) {
        if (input[i] != '0' && input[i] != '1') {
            cout << "解码失败 - 输入包含非0/1字符!" << endl;
            cout << "================================================" << endl;
            return;
        }
    }

    // 从根结点开始解码
    int root = m - 1;   // 根结点下标
    string result;
    int    current = root;

    for (size_t i = 0; i < input.length(); i++) {
        if (input[i] == '0') {
            current = ht[current].lchild;
        } else {
            current = ht[current].rchild;
        }

        // 检查是否到达叶子结点
        if (current < n) {
            // 找到叶子结点
            result += ht[current].ch;
            current = root;   // 回到根结点，继续解码下一个字符
        } else if (current == -1) {
            // 不应该发生
            cout << "解码失败 - 编码不匹配!" << endl;
            cout << "================================================" << endl;
            return;
        }
    }

    // 如果解码结束后不在根结点，说明编码不完整
    if (current != root) {
        cout << "解码失败 - 编码串不完整!" << endl;
        cout << "================================================" << endl;
        return;
    }

    cout << "解码结果: " << result << endl;
    cout << "================================================" << endl;
}

