// 在 [0, range) 范围内选择 parent=-1 且权值最小的两个结点
// s1 存放最小的，s2 存放次小的
// 要求：s1 的权值 <= s2 的权值，若权值相同则先出现的为 s1
void Select(int range, int &s1, int &s2) {
    int min1 = 0x7fffffff;  // 极大值
    int min2 = 0x7fffffff;

    s1 = -1;
    s2 = -1;

    for (int i = 0; i < range; i++) {
        if (ht[i].parent == -1) {  // 只考虑根结点
            int w = ht[i].weight;
            int o = ht[i].order;

            if (w < min1) {
                // 原来的最小变成次小
                min2 = min1;
                s2   = s1;
                min1 = w;
                s1   = i;
            } else if (w == min1 && s1 != -1) {
                // 权值相同，先出现的 (order小的) 优先
                if (o < ht[s1].order) {
                    min2 = min1;
                    s2   = s1;
                    min1 = w;
                    s1   = i;
                } else {
