                    if (w < min2 || (w == min2 && s2 != -1 && o < ht[s2].order)) {
                        min2 = w;
                        s2   = i;
                    } else if (min2 == 0x7fffffff) {
                        min2 = w;
                        s2   = i;
                    }
                }
            } else if (w < min2) {
                min2 = w;
