            } else if (w == min2 && s2 != -1) {
                // 权值相同
                if (o < ht[s2].order) {
                    min2 = w;
                    s2   = i;
                }
            }
        }
    }

    // 确保 s1 的权值 <= s2 的权值
    // 若权值相等，s1 的 order < s2 的 order (先出现的在左)
    if (s1 != -1 && s2 != -1) {
        if (ht[s1].weight > ht[s2].weight) {
            int tmp = s1;
            s1 = s2;
            s2 = tmp;
        } else if (ht[s1].weight == ht[s2].weight) {
            if (ht[s1].order > ht[s2].order) {
                int tmp = s1;
                s1 = s2;
                s2 = tmp;
