                  (ht[i].weight == ht[s1].weight && ht[i].order < ht[s1].order)) {
            // i 比 s1 更小
            s2 = s1;
            s1 = i;
        } else if (s2 == -1) {
            s2 = i;
        } else if (ht[i].weight < ht[s2].weight ||
                  (ht[i].weight == ht[s2].weight && ht[i].order < ht[s2].order)) {
            s2 = i;
        }
    }
}

// ============ 创建哈夫曼树 ============
void CreateHT() {
    InitHT();

    int s1, s2;
    for (int i = n; i < m; i++) {
        Select(i, s1, s2);

        ht[s1].parent = i;
        ht[s2].parent = i;

        ht[i].lchild = s1;   // 较小的在左
        ht[i].rchild = s2;   // 较大的在右
        ht[i].weight = ht[s1].weight + ht[s2].weight;
    }
}

// ============ 生成哈夫曼编码 (从叶子向根回溯) ============
void CreateHTCode() {
    for (int i = 0; i < n; i++) {
        hc[i].ch = chars[i];

        char temp[MAXLEN];
        int  pos  = 0;
        int  cur  = i;
        int  par  = ht[cur].parent;

        while (par != -1) {
            if (ht[par].lchild == cur) {
                temp[pos++] = '0';
            } else {
                temp[pos++] = '1';
            }
            cur = par;
            par = ht[cur].parent;
        }

        // 反转
        hc[i].len = pos;
        for (int j = 0; j < pos; j++) {
            hc[i].bits[j] = temp[pos - 1 - j];
        }
        hc[i].bits[pos] = '\0';
    }
}

// ============ 打印哈夫曼树结构 (横向缩进) ============
void PrintTreeRec(int idx, int depth) {
    if (idx == -1) return;

    // 先打印右子树 (显示在上方)
    PrintTreeRec(ht[idx].rchild, depth + 1);

    // 缩进
    for (int i = 0; i < depth; i++) {
        cout << "        ";
    }

    // 显示结点
    if (idx < n) {
        // 叶子结点
        char c = ht[idx].ch;
        cout << "(" << idx << ") ";
        if (c == ' ')
            cout << "<SP>:";
        else
            cout << c << ":";
        cout << ht[idx].weight;
        // 显示编码
        for (int k = 0; k < n; k++) {
            if (hc[k].ch == c) {
                cout << "  [" << hc[k].bits << "]";
                break;
            }
        }
    } else {
        // 内部结点
        cout << "(" << idx << ") [" << ht[idx].weight << "]";
    }
    cout << endl;

    // 再打印左子树 (显示在下方)
    PrintTreeRec(ht[idx].lchild, depth + 1);
}

void PrintHT() {
    cout << endl;
    cout << "================================================" << endl;
    cout << "       哈夫曼树结构 (横向缩进显示)" << endl;
    cout << "  说明: 从上到下是根->叶子的方向" << endl;
    cout << "        叶子: (下标) 字符:权值 [编码]" << endl;
    cout << "        内部: (下标) [权值]" << endl;
    cout << "================================================" << endl;
    cout << endl;

    PrintTreeRec(m - 1, 0);

    cout << endl;
    cout << "================================================" << endl;
}

// ============ 打印字符及哈夫曼编码 ============
void PrintCode() {
    cout << endl;
    cout << "================================================" << endl;
    cout << "          字符及其哈夫曼编码表" << endl;
    cout << "================================================" << endl;
    cout << left;
    cout << setw(10) << "字符"
         << setw(10) << "权值"
         << setw(20) << "哈夫曼编码"
         << "编码长度" << endl;
    cout << string(55, '-') << endl;

    for (int i = 0; i < n; i++) {
        cout << setw(10);
        if (hc[i].ch == ' ')
            cout << "<SP>";
        else
            cout << hc[i].ch;

        cout << setw(10) << ht[i].weight;
        cout << setw(20) << hc[i].bits;
        cout << hc[i].len << endl;
    }
    cout << string(55, '-') << endl;
    cout << "共 " << n << " 个字符" << endl;
    cout << "================================================" << endl;
}

// ============ 计算指定字符串的传输长度 ============
void CalcTransLength(const char *str) {
    // 建立字符 -> 编码下标 的快速映射
    int map[256];
    for (int i = 0; i < 256; i++) map[i] = -1;
    for (int i = 0; i < n; i++) {
        map[(unsigned char)hc[i].ch] = i;
    }

    cout << endl;
    cout << "================================================" << endl;
    cout << "  计算报文传输长度" << endl;
    cout << "  原文: " << str << endl;
    cout << "================================================" << endl;
    cout << left;

    int totalBits = 0;
    int slen = (int)strlen(str);

    cout << endl << "逐字符编码:" << endl;
    cout << setw(8) << "字符"
         << setw(22) << "编码"
         << "位数" << endl;
    cout << string(42, '-') << endl;

    for (int i = 0; i < slen; i++) {
        char c = str[i];
        int  idx = map[(unsigned char)c];

        if (idx == -1) {
            cout << setw(8) << c << " (不在字符集中，跳过)" << endl;
            continue;
        }

        cout << setw(8);
        if (c == ' ') cout << "<SP>"; else cout << c;
        cout << setw(22) << hc[idx].bits;
        cout << hc[idx].len << endl;

        totalBits += hc[idx].len;
    }

    cout << string(42, '-') << endl;
    cout << "总报文传输长度: " << totalBits << " bits" << endl;
    cout << "================================================" << endl;
}

// ============ 解码用户输入的01串 ============
void DecodeInput() {
    string input;
    cout << endl;
    cout << "================================================" << endl;
    cout << "           哈夫曼解码" << endl;
    cout << "================================================" << endl;
    cout << "请输入01编码串: ";
    getline(cin, input);

    if (input.empty()) {
        cout << "输入为空!" << endl;
        cout << "================================================" << endl;
        return;
    }

    // 校验输入
    for (size_t i = 0; i < input.length(); i++) {
        if (input[i] != '0' && input[i] != '1') {
            cout << "解码失败 - 输入包含非0/1字符!" << endl;
            cout << "================================================" << endl;
            return;
        }
    }

    // 从根开始解码
    int    root    = m - 1;
    string result;
    int    current = root;

    for (size_t i = 0; i < input.length(); i++) {
        if (input[i] == '0') {
            current = ht[current].lchild;
        } else {
            current = ht[current].rchild;
        }

        if (current == -1) {
            cout << "解码失败 - 遇到无效编码路径!" << endl;
            cout << "================================================" << endl;
            return;
        }

        if (current < n) {
            // 到达叶子结点，输出字符
            result += ht[current].ch;
            current = root;
        }
    }

    // 结束后必须回到根
    if (current != root) {
        cout << "解码失败 - 编码串不完整，剩余位不足以构成完整字符!" << endl;
        cout << "================================================" << endl;
        return;
    }

    cout << endl << "解码结果: " << result << endl;
    cout << "================================================" << endl;
}

