 *   2. 打印哈夫曼树结构
 *   3. 打印所有字符及其哈夫曼编码
 *   4. (选做) 计算 "THIS PROGRAM IS MY FAVORITE" 的总报文传输长度
 *   5. (选做) 对用户输入的01串进行解码
 *
 * 构建规则：
 *   左孩子权值 <= 右孩子权值
 *   权值相同时，原序列中先出现的作为左孩子
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAXNODE 100      /* 最大结点数 (27叶子 + 26内部 = 53) */
#define MAXLEN  200      /* 最大编码长度 */

/* ============ 哈夫曼树结点 ============ */
typedef struct {
    char  ch;            /* 字符 (叶子结点有效) */
    int   weight;        /* 权值 */
