162	            *s1 = i;
163	        } else if (ht[i].weight < ht[*s1].weight ||
164	                  (ht[i].weight == ht[*s1].weight && ht[i].order < ht[*s1].order)) {
165	            /* i 比 *s1 更小 */
166	            *s2 = *s1;
167	            *s1 = i;
168	        } else if (*s2 == -1) {
169	            *s2 = i;
170	        } else if (ht[i].weight < ht[*s2].weight ||
171	                  (ht[i].weight == ht[*s2].weight && ht[i].order < ht[*s2].order)) {
172	            *s2 = i;
