197	void CreateHTCode(void) {
198	    int i, j;
199	    int cur, par, pos;
200	    char temp[MAXLEN];
201	
202	    for (i = 0; i < n; i++) {
203	        hc[i].ch = chars[i];
204	
205	        pos = 0;
206	        cur = i;
207	        par = ht[cur].parent;
208	
209	        while (par != -1) {
210	            if (ht[par].lchild == cur) {
211	                temp[pos++] = '0';
212	            } else {
213	                temp[pos++] = '1';
214	            }
215	            cur = par;
216	            par = ht[cur].parent;
217	        }
218	
219	        /* 反转 */
220	        hc[i].len = pos;
221	        for (j = 0; j < pos; j++) {
222	            hc[i].bits[j] = temp[pos - 1 - j];
223	        }
224	        hc[i].bits[pos] = '\0';
225	    }
226	}
