355	void DecodeInput(void) {
356	    char input[MAXLEN];
357	    char result[MAXLEN];
358	    int  i, len, root, current, resPos;
359	    int  valid;
360	
361	    printf("\n");
362	    printf("================================================\n");
363	    printf("           哈夫曼解码\n");
364	    printf("================================================\n");
365	    printf("请输入01编码串: ");
366	    fgets(input, MAXLEN, stdin);
367	
368	    /* 去掉 fgets 读入的换行符 */
369	    len = (int)strlen(input);
370	    if (len > 0 && input[len - 1] == '\n') {
371	        input[len - 1] = '\0';
372	        len--;
373	    }
374	
375	    if (len == 0) {
376	        printf("输入为空!\n");
377	        printf("================================================\n");
378	        return;
379	    }
380	
381	    /* 校验输入 */
382	    valid = 1;
383	    for (i = 0; i < len; i++) {
384	        if (input[i] != '0' && input[i] != '1') {
385	            valid = 0;
386	            break;
387	        }
388	    }
389	    if (!valid) {
390	        printf("解码失败 - 输入包含非0/1字符!\n");
391	        printf("================================================\n");
392	        return;
393	    }
394	
395	    /* 从根开始解码 */
396	    root    = m - 1;
397	    current = root;
398	    resPos  = 0;
399	    result[0] = '\0';
400	
401	    for (i = 0; i < len; i++) {
402	        if (input[i] == '0') {
403	            current = ht[current].lchild;
404	        } else {
405	            current = ht[current].rchild;
406	        }
407	
408	        if (current == -1) {
409	            printf("解码失败 - 遇到无效编码路径!\n");
410	            printf("================================================\n");
411	            return;
412	        }
413	
414	        if (current < n) {
415	            /* 到达叶子结点，输出字符 */
416	            result[resPos++] = ht[current].ch;
417	            result[resPos] = '\0';
418	            current = root;
419	        }
420	    }
421	
422	    /* 结束后必须回到根 */
423	    if (current != root) {
424	        printf("解码失败 - 编码串不完整，剩余位不足以构成完整字符!\n");
425	        printf("================================================\n");
426	        return;
427	    }
428	
429	    printf("\n解码结果: %s\n", result);
430	    printf("================================================\n");
431	}
