1	/*
2	 * 哈夫曼树应用程序 (C语言版) - 数据结构与算法课程设计
3	 *
4	 * 功能：
5	 *   1. 根据给定的字符频率创建哈夫曼树
6	 *   2. 打印哈夫曼树结构
7	 *   3. 打印所有字符及其哈夫曼编码
8	 *   4. (选做) 计算 "THIS PROGRAM IS MY FAVORITE" 的总报文传输长度
9	 *   5. (选做) 对用户输入的01串进行解码
10	 *
11	 * 构建规则：
12	 *   左孩子权值 <= 右孩子权值
13	 *   权值相同时，原序列中先出现的作为左孩子
14	 */
15	
16	#define _CRT_SECURE_NO_WARNINGS   /* VS安全函数警告抑制 */
17	#include <stdio.h>
18	#include <stdlib.h>
19	#include <string.h>
20	
21	#define MAXNODE 100      /* 最大结点数 (27叶子 + 26内部 = 53) */
22	#define MAXLEN  200      /* 最大编码长度 */
23	
24	/* ============ 哈夫曼树结点 ============ */
25	typedef struct {
26	    char  ch;            /* 字符 (叶子结点有效) */
27	    int   weight;        /* 权值 */
28	    int   parent;        /* 双亲下标, -1表示无 */
29	    int   lchild;        /* 左孩子下标, -1表示无 */
30	    int   rchild;        /* 右孩子下标, -1表示无 */
31	    int   order;         /* 在原序列中的出现次序 (权值相同时判定左右) */
32	} HTNode;
33	
34	/* ============ 哈夫曼编码表项 ============ */
35	typedef struct {
36	    char ch;             /* 字符 */
37	    char bits[MAXLEN];   /* 编码01串 */
38	    int  len;            /* 编码长度 */
39	} HTCode;
40	
41	/* ============ 全局数据 ============ */
42	HTNode ht[MAXNODE];      /* 哈夫曼树 (数组存储) */
43	HTCode hc[27];           /* 27个字符的编码 */
44	int    n = 27;           /* 叶子结点数 */
45	int    m;                /* 总结点数 = 2*n - 1 = 53 */
46	
47	/* 字符集: 空格 + 26个大写英文字母 */
48	char chars[27] = {
49	    ' ', 'A','B','C','D','E','F','G','H','I',
50	    'J','K','L','M','N','O','P','Q','R','S',
51	    'T','U','V','W','X','Y','Z'
52	};
53	
54	/* 对应频率 */
55	int weights[27] = {
56	    186, 64, 13, 22, 32, 103, 21, 15,
57	     47, 57,  1,  5, 32,  20, 57, 63,
58	     15,  1, 48, 51, 80,  23,  8, 18,
59	      1, 16,  1
60	};
61	
62	/* ============ 函数声明 ============ */
63	void InitHT(void);
64	void CreateHT(void);
65	void Select(int range, int *s1, int *s2);
66	void CreateHTCode(void);
67	void PrintHT(void);
68	void PrintCode(void);
69	void CalcTransLength(const char *str);
70	void DecodeInput(void);
71	void PrintMenu(void);
72	
73	/* 递归打印树的辅助函数 */
74	void PrintTreeRec(int idx, int depth);
75	
76	/* ============ 主函数 ============ */
77	int main(void) {
78	    int choice;
79	
80	    printf("\n");
81	    printf("================================================\n");
82	    printf("      哈夫曼树应用程序 (Huffman Tree)\n");
83	    printf("      数据结构与算法课程设计\n");
84	    printf("================================================\n");
85	
86	    /* 1. 创建哈夫曼树 */
87	    CreateHT();
88	
89	    /* 2. 生成哈夫曼编码 */
90	    CreateHTCode();
91	
92	    /* 3. 打印哈夫曼树结构 */
93	    PrintHT();
94	
95	    /* 4. 打印字符及其哈夫曼编码表 */
96	    PrintCode();
97	
98	    /* 5. 交互菜单 */
99	    do {
100	        PrintMenu();
101	        printf("请输入选择 (0-2): ");
102	        scanf("%d", &choice);
103	        getchar();  /* 清除缓冲区中的换行符 */
104	
105	        switch (choice) {
106	            case 1:
107	                CalcTransLength("THIS PROGRAM IS MY FAVORITE");
108	                break;
109	            case 2:
110	                DecodeInput();
111	                break;
112	            case 0:
113	                printf("\n程序结束，谢谢使用!\n");
114	                break;
115	            default:
116	                printf("无效选择，请重新输入!\n");
117	        }
118	    } while (choice != 0);
119	
120	    system("pause");  /* VS运行后暂停，防止控制台闪退 */
121	    return 0;
122	}
123	
124	/* ============ 初始化哈夫曼树 ============ */
125	void InitHT(void) {
126	    int i;
127	
128	    m = 2 * n - 1;  /* 53 */
129	
130	    /* 初始化叶子结点 (0 ~ 26) */
131	    for (i = 0; i < n; i++) {
132	        ht[i].ch     = chars[i];
133	        ht[i].weight = weights[i];
134	        ht[i].parent = -1;
135	        ht[i].lchild = -1;
136	        ht[i].rchild = -1;
137	        ht[i].order  = i;
138	    }
139	
140	    /* 初始化内部结点 (27 ~ 52) */
141	    for (i = n; i < m; i++) {
142	        ht[i].ch     = '#';
143	        ht[i].weight = 0;
144	        ht[i].parent = -1;
145	        ht[i].lchild = -1;
146	        ht[i].rchild = -1;
147	        ht[i].order  = i;
148	    }
149	}
150	
151	/* ============ 选择两个权值最小的根结点 ============ */
152	/* 在 [0, range) 中选 parent==-1 的结点, 按 (权值, order) 比较 */
153	/* *s1: 最小的, *s2: 次小的 */
154	void Select(int range, int *s1, int *s2) {
155	    int i;
156	
157	    *s1 = -1;
158	    *s2 = -1;
159	
160	    for (i = 0; i < range; i++) {
161	        if (ht[i].parent != -1) continue;
162	
163	        if (*s1 == -1) {
164	            *s1 = i;
165	        } else if (ht[i].weight < ht[*s1].weight ||
166	                  (ht[i].weight == ht[*s1].weight && ht[i].order < ht[*s1].order)) {
167	            /* i 比 *s1 更小 */
168	            *s2 = *s1;
169	            *s1 = i;
170	        } else if (*s2 == -1) {
171	            *s2 = i;
172	        } else if (ht[i].weight < ht[*s2].weight ||
173	                  (ht[i].weight == ht[*s2].weight && ht[i].order < ht[*s2].order)) {
174	            *s2 = i;
175	        }
176	    }
177	}
178	
179	/* ============ 创建哈夫曼树 ============ */
180	void CreateHT(void) {
181	    int i;
182	    int s1, s2;
183	
184	    InitHT();
185	
186	    for (i = n; i < m; i++) {
187	        Select(i, &s1, &s2);
188	
189	        ht[s1].parent = i;
190	        ht[s2].parent = i;
191	
192	        ht[i].lchild = s1;   /* 较小的在左 */
193	        ht[i].rchild = s2;   /* 较大的在右 */
194	        ht[i].weight = ht[s1].weight + ht[s2].weight;
195	    }
196	}
197	
198	/* ============ 生成哈夫曼编码 (从叶子向根回溯) ============ */
199	void CreateHTCode(void) {
200	    int i, j;
201	    int cur, par, pos;
202	    char temp[MAXLEN];
203	
204	    for (i = 0; i < n; i++) {
205	        hc[i].ch = chars[i];
206	
207	        pos = 0;
208	        cur = i;
209	        par = ht[cur].parent;
210	
211	        while (par != -1) {
212	            if (ht[par].lchild == cur) {
213	                temp[pos++] = '0';
214	            } else {
215	                temp[pos++] = '1';
216	            }
217	            cur = par;
218	            par = ht[cur].parent;
219	        }
220	
221	        /* 反转 */
222	        hc[i].len = pos;
223	        for (j = 0; j < pos; j++) {
224	            hc[i].bits[j] = temp[pos - 1 - j];
225	        }
226	        hc[i].bits[pos] = '\0';
227	    }
228	}
229	
230	/* ============ 打印哈夫曼树结构 (横向缩进) ============ */
231	void PrintTreeRec(int idx, int depth) {
232	    int i;
233	    char c;
234	
235	    if (idx == -1) return;
236	
237	    /* 先打印右子树 (显示在上方) */
238	    PrintTreeRec(ht[idx].rchild, depth + 1);
239	
240	    /* 缩进 */
241	    for (i = 0; i < depth; i++) {
242	        printf("        ");
243	    }
244	
245	    /* 显示结点 */
246	    if (idx < n) {
247	        /* 叶子结点 */
248	        c = ht[idx].ch;
249	        printf("(%d) ", idx);
250	        if (c == ' ')
251	            printf("<SP>:");
252	        else
253	            printf("%c:", c);
254	        printf("%d", ht[idx].weight);
255	        /* 显示编码 (hc与ht叶子下标一一对应) */
256	        printf("  [%s]", hc[idx].bits);
257	    } else {
