153	/* 在 [0, range) 中选 parent==-1 的结点, 按 (权值, order) 比较 */
154	/* *s1: 最小的, *s2: 次小的 */
155	void Select(int range, int *s1, int *s2) {
156	    int i;
157	
158	    *s1 = -1;
159	    *s2 = -1;
160	
161	    for (i = 0; i < range; i++) {
