165	            *s1 = i;
166	        } else if (ht[i].weight < ht[*s1].weight ||
167	                  (ht[i].weight == ht[*s1].weight && ht[i].order < ht[*s1].order)) {
168	            /* i 比 *s1 更小 */
169	            *s2 = *s1;
170	            *s1 = i;
171	        } else if (*s2 == -1) {
172	            *s2 = i;
173	        } else if (ht[i].weight < ht[*s2].weight ||
174	                  (ht[i].weight == ht[*s2].weight && ht[i].order < ht[*s2].order)) {
175	            *s2 = i;
