362	    int  i, len, root, current, resPos;
363	    int  valid;
364	
365	    printf("\n");
366	    printf("================================================\n");
367	    printf("           哈夫曼解码\n");
368	    printf("================================================\n");
369	    printf("请输入01编码串: ");
370	    fgets(input, MAXLEN, stdin);
371	
372	    /* 去掉 fgets 读入的换行符 */
373	    len = (int)strlen(input);
374	    if (len > 0 && input[len - 1] == '\n') {
375	        input[len - 1] = '\0';
376	        len--;
377	    }
378	
379	    if (len == 0) {
380	        printf("输入为空!\n");
381	        printf("================================================\n");
382	        return;
383	    }
384	
385	    /* 校验输入 */
386	    valid = 1;
387	    for (i = 0; i < len; i++) {
388	        if (input[i] != '0' && input[i] != '1') {
389	            valid = 0;
390	            break;
391	        }
392	    }
393	    if (!valid) {
394	        printf("解码失败 - 输入包含非0/1字符!\n");
395	        printf("================================================\n");
396	        return;
397	    }
398	
399	    /* 从根开始解码 */
400	    root    = m - 1;
401	    current = root;
402	    resPos  = 0;
403	    result[0] = '\0';
404	
405	    for (i = 0; i < len; i++) {
406	        if (input[i] == '0') {
407	            current = ht[current].lchild;
408	        } else {
409	            current = ht[current].rchild;
410	        }
411	
412	        if (current == -1) {
413	            printf("解码失败 - 遇到无效编码路径!\n");
414	            printf("================================================\n");
415	            return;
416	        }
417	
418	        if (current < n) {
419	            /* 到达叶子结点，输出字符 */
420	            result[resPos++] = ht[current].ch;
421	            result[resPos] = '\0';
422	            current = root;
423	        }
424	    }
425	
426	    /* 结束后必须回到根 */
427	    if (current != root) {
428	        printf("解码失败 - 编码串不完整，剩余位不足以构成完整字符!\n");
429	        printf("================================================\n");
430	        return;
431	    }
432	
433	    printf("\n解码结果: %s\n", result);
434	    printf("================================================\n");
435	}
