import zipfile, xml.etree.ElementTree as ET, os, sys

def extract_docx_text(filepath):
    with zipfile.ZipFile(filepath, 'r') as z:
        xml_content = z.read('word/document.xml')
        tree = ET.fromstring(xml_content)
        ns = {'w': 'http://schemas.openxmlformats.org/wordprocessingml/2006/main'}
        texts = []
        for p in tree.iter('{http://schemas.openxmlformats.org/wordprocessingml/2006/main}p'):
            para_text = ''
            for t in p.iter('{http://schemas.openxmlformats.org/wordprocessingml/2006/main}t'):
                if t.text:
                    para_text += t.text
            texts.append(para_text)
        return '\n'.join(texts)

def extract_pptx_text(filepath):
    with zipfile.ZipFile(filepath, 'r') as z:
        texts = []
        for i in range(1, 100):
            try:
                xml_content = z.read(f'ppt/slides/slide{i}.xml')
                tree = ET.fromstring(xml_content)
                ns = {'a': 'http://schemas.openxmlformats.org/drawingml/2006/main'}
                for t in tree.iter('{http://schemas.openxmlformats.org/drawingml/2006/main}t'):
                    if t.text:
                        texts.append(t.text)
            except:
                break
        return '\n'.join(texts)

# Extract docx
print('=== REPORT TEMPLATE (docx) ===')
